+// ReloadStatus describes the most recent transactional configuration reload.
+type ReloadStatus struct {
+	LastReloadID         string           `json:"last_reload_id"`
+	LastReloadSuccessful bool             `json:"last_reload_successful"`
+	ErrorCategory        string           `json:"error_category"`
+	ErrorMessage         string           `json:"error_message"`
+	AppliedReloaders     []string         `json:"applied_reloaders"`
+	RollbackAttempted    bool             `json:"rollback_attempted"`
+	RollbackSuccessful   bool             `json:"rollback_successful"`
+	FailedReloader       string           `json:"failed_reloader"`
+	ReloaderTimingsMS    map[string]int64 `json:"reloader_timings_ms"`
+}
+
+// ReloadStatusTracker keeps a reload status in memory and, after a reload has
+// been attempted, persists it atomically for inspection following a restart.
+type ReloadStatusTracker struct {
+	mu     sync.RWMutex
+	status ReloadStatus
+	path   string
+	logger *slog.Logger
+}
+
+func NewReloadStatusTracker(storageDir string, logger *slog.Logger) *ReloadStatusTracker {
+	t := &ReloadStatusTracker{
+		status: ReloadStatus{AppliedReloaders: []string{}, ReloaderTimingsMS: map[string]int64{}, ErrorCategory: "none"},
+		path:   filepath.Join(storageDir, "reload-status.json"),
+		logger: logger,
+	}
+	b, err := os.ReadFile(t.path)
+	if err != nil {
+		if !os.IsNotExist(err) {
+			logger.Warn("Unable to read persisted reload status", "err", err)
+		}
+		return t
+	}
+	var status ReloadStatus
+	if err := json.Unmarshal(b, &status); err != nil {
+		logger.Warn("Unable to decode persisted reload status", "err", err)
+		return t
+	}
+	if status.AppliedReloaders == nil {
+		status.AppliedReloaders = []string{}
+	}
+	if status.ReloaderTimingsMS == nil {
+		status.ReloaderTimingsMS = map[string]int64{}
+	}
+	t.status = status
+	return t
+}
+
+func (t *ReloadStatusTracker) Get() ReloadStatus {
+	t.mu.RLock()
+	defer t.mu.RUnlock()
+	s := t.status
+	s.AppliedReloaders = append([]string(nil), s.AppliedReloaders...)
+	s.ReloaderTimingsMS = make(map[string]int64, len(t.status.ReloaderTimingsMS))
+	for k, v := range t.status.ReloaderTimingsMS {
+		s.ReloaderTimingsMS[k] = v
+	}
+	return s
+}
+
+func (t *ReloadStatusTracker) Set(status ReloadStatus) {
+	t.mu.Lock()
+	t.status = status
+	b, err := json.Marshal(status)
+	if err == nil {
+		err = os.MkdirAll(filepath.Dir(t.path), 0o755)
+	}
+	if err == nil {
+		err = os.WriteFile(t.path+".tmp", b, 0o644)
+	}
+	if err == nil {
+		err = os.Rename(t.path+".tmp", t.path)
+	}
+	t.mu.Unlock()
+	if err != nil {
+		t.logger.Warn("Unable to persist reload status", "err", err)
+	}
+}
