+// transactionalConfigReloader applies a configuration in order and restores the
+// last fully applied configuration when a later component rejects a reload.
+type transactionalConfigReloader struct {
+	filename               string
+	enableExemplarStorage bool
+	logger                 *slog.Logger
+	noStepSubqueryInterval *safePromQLNoStepSubqueryInterval
+	status                 *web.ReloadStatusTracker
+	reloaders              []reloader
+	lastKnownGood          *config.Config
+}
+
+func (r *transactionalConfigReloader) load() (*config.Config, error) {
+	conf, err := config.LoadFile(r.filename, agentMode, r.logger)
+	if err != nil {
+		return nil, fmt.Errorf("couldn't load configuration (--config.file=%q): %w", r.filename, err)
+	}
+	if r.enableExemplarStorage && conf.StorageConfig.ExemplarsConfig == nil {
+		conf.StorageConfig.ExemplarsConfig = &config.DefaultExemplarsConfig
+	}
+	return conf, nil
+}
+
+func (r *transactionalConfigReloader) apply(conf *config.Config, timings map[string]int64, applied *[]string) (string, error) {
+	for _, rl := range r.reloaders {
+		start := time.Now()
+		err := rl.reloader(conf)
+		timings[rl.name] = durationToInt64Millis(time.Since(start))
+		if err != nil {
+			return rl.name, err
+		}
+		*applied = append(*applied, rl.name)
+	}
+	updateGoGC(conf, r.logger)
+	r.noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
+	return "", nil
+}
+
+// LoadInitial establishes the configuration eligible for later rollback. It
+// deliberately does not create a reload status record.
+func (r *transactionalConfigReloader) LoadInitial() error {
+	conf, err := r.load()
+	if err != nil {
+		return err
+	}
+	_, err = r.apply(conf, map[string]int64{}, &[]string{})
+	if err != nil {
+		return err
+	}
+	r.lastKnownGood = conf
+	return nil
+}
+
+func (r *transactionalConfigReloader) Reload(callback func(bool)) error {
+	status := web.ReloadStatus{
+		LastReloadID: time.Now().UTC().Format(time.RFC3339), ErrorCategory: "none",
+		AppliedReloaders: []string{}, ReloaderTimingsMS: map[string]int64{},
+	}
+	conf, err := r.load()
+	if err != nil {
+		status.ErrorCategory = "load_error"
+		status.ErrorMessage = err.Error()
+		r.status.Set(status)
+		configSuccess.Set(0)
+		callback(false)
+		return err
+	}
+
+	failedReloader, err := r.apply(conf, status.ReloaderTimingsMS, &status.AppliedReloaders)
+	if err == nil {
+		status.LastReloadSuccessful = true
+		r.lastKnownGood = conf
+		r.status.Set(status)
+		configSuccess.Set(1)
+		configSuccessTime.SetToCurrentTime()
+		callback(true)
+		return nil
+	}
+
+	status.ErrorCategory = "apply_error"
+	status.ErrorMessage = err.Error()
+	status.FailedReloader = failedReloader
+	if len(status.AppliedReloaders) > 0 && r.lastKnownGood != nil {
+		status.RollbackAttempted = true
+		var rolledBack []string
+		rollbackFailed, rollbackErr := r.apply(r.lastKnownGood, map[string]int64{}, &rolledBack)
+		if rollbackErr == nil {
+			status.RollbackSuccessful = true
+		} else {
+			status.ErrorCategory = "rollback_error"
+			status.ErrorMessage = fmt.Sprintf("apply failed in %s: %v; rollback failed in %s: %v", failedReloader, err, rollbackFailed, rollbackErr)
+		}
+	}
+	r.status.Set(status)
+	configSuccess.Set(0)
+	callback(false)
+	return fmt.Errorf("failed to apply configuration in %s: %w", failedReloader, err)
+}

